            .@"eof" => 1,
            .@"ident" => self.identToSymbol(token),
            .@"newline" => 55,
            .@"string_sq" => 60,
            .@"string_dq" => 61,
            .@"indent" => 66,
            .@"outdent" => 67,
            .@"integer" => 88,
            .@"minus_prefix" => 115,
            .@"real" => 123,
            .@"true" => 124,
            .@"false" => 125,
