            .@"question" => 83,
            .@"star" => 84,
            .@"lbracket" => 86,
            .@"rbracket" => 87,
            .@"bar" => 91,
            .@"dot" => 98,
            .@"lparen" => 119,
            .@"rparen" => 120,
            .@"at" => 129,
            .@"lbrace" => 130,
            .@"rbrace" => 133,
            .@"lt" => 152,
            .@"gt" => 153,
            .@"plus" => 156,
            .@"minus" => 157,
            .@"slash" => 158,
            .@"percent" => 159,
            .@"arrow" => 81,
            .@"dotdot" => 99,
            .@"fat_arrow" => 100,
            .@"nullish" => 101,
